const API = {
    login: (username, password) =>
        fetch("/api/auth/login", {
            method: "POST",
            headers: {"Content-Type": "application/json"},
            body: JSON.stringify({ username, password })
        }).then(r => r.json()),

    register: (username, password) =>
        fetch("/api/auth/register", {
            method: "POST",
            headers: {"Content-Type": "application/json"},
            body: JSON.stringify({ username, password })
        }).then(r => r.json())
};

export default API;
